steps.run:
const trace = ctx._trace || {};
const tc = trace.titleChangesSoFar || [];
const total = trace.messages || 0;
const changes = tc.length;
const expected = Math.floor(total / 3);
const timeline = tc.map(function(c){ return { afterMessage: c.afterMessage, from: c.from, to: c.to }; });
const pass = changes >= expected;
const verdict = {
    totalMessages: total,
    titleChanges: changes,
    expectedMinChanges: expected,
    pass: pass,
    changesTimeline: timeline,
    reason: pass
        ? ('OK: título cambió al menos una vez cada 3 mensajes.')
        : ('FAIL: sólo ' + changes + ' cambios en ' + total + ' mensajes (esperaba >= ' + expected + '). Timeline: ' + JSON.stringify(timeline)),
};
ctx.vars.verdict = verdict;
return { verdict: verdict };
